#!/usr/bin/env node
/* sprint4.mjs — applies Sprint 4 (red flags + PDF diligence report + export pack). */
import { mkdirSync, writeFileSync } from "node:fs";
import { dirname } from "node:path";
const FILES=[
  ["package.json", ""],
  ["PROJECT_LOG.md", ""],
  ["src/main/services/intelligence/redflags.ts", ""],
  ["src/main/services/export/report.ts", ""],
  ["src/main/services/export/bundle.ts", ""],
  ["src/main/ipc/index.ts", ""],
  ["src/preload/index.ts", ""],
  ["src/preload/index.d.ts", ""],
  ["src/renderer/src/App.tsx", ""],
  ["src/renderer/src/assets/main.css", ""]
];
let n=0; for(const [rel,b64] of FILES){ mkdirSync(dirname(rel),{recursive:true}); writeFileSync(rel,Buffer.from(b64,"base64")); n++; }
console.log(`✅ Sprint 4 applied: ${n} files written/updated.`);
console.log("Next: npm install  &&  npm run dev");
